{"ideviceId":"202604281456135527CA","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="oxidacion-oxoacidos" style="font-family: Arial, sans-serif; line-height: 1.7; background: #ffffff; border: 1px solid #e5e7eb; border-radius: 18px; padding: 22px;">
<h2 style="color: #1d4ed8; margin-top: 0;">Practica: números de oxidación en oxoácidos</h2>
<p>Calcula el número de oxidación del elemento central e introduce solo el número. Por ejemplo: si es +6, escribe <strong>6</strong>.</p>
<div id="ejerciciosOxidacion"></div>
<button onclick="reiniciarOxidacion()" style="margin-top: 18px; background: #2563eb; color: white; border: none; padding: 12px 18px; border-radius: 12px; font-weight: bold; cursor: pointer;"> Reiniciar </button>
<p id="resultadoOxidacion" style="font-weight: bold; font-size: 18px; margin-top: 16px;"></p>
</div>
<p>
<script>
const ejerciciosOxidacion = [
  { formula:"HNO3", elemento:"N", respuesta:5, explicacion:"(+1) + x + 3(-2) = 0 → x = +5." },
  { formula:"HNO2", elemento:"N", respuesta:3, explicacion:"(+1) + x + 2(-2) = 0 → x = +3." },
  { formula:"H2SO4", elemento:"S", respuesta:6, explicacion:"2(+1) + x + 4(-2) = 0 → x = +6." },
  { formula:"H2SO3", elemento:"S", respuesta:4, explicacion:"2(+1) + x + 3(-2) = 0 → x = +4." },
  { formula:"H3PO4", elemento:"P", respuesta:5, explicacion:"3(+1) + x + 4(-2) = 0 → x = +5." },
  { formula:"H3PO3", elemento:"P", respuesta:3, explicacion:"3(+1) + x + 3(-2) = 0 → x = +3." },
  { formula:"HClO4", elemento:"Cl", respuesta:7, explicacion:"(+1) + x + 4(-2) = 0 → x = +7." },
  { formula:"HClO", elemento:"Cl", respuesta:1, explicacion:"(+1) + x + (-2) = 0 → x = +1." },
  { formula:"H2Cr2O7", elemento:"Cr", respuesta:6, explicacion:"2(+1) + 2x + 7(-2) = 0 → 2x = 12 → x = +6." },
  { formula:"HMnO4", elemento:"Mn", respuesta:7, explicacion:"(+1) + x + 4(-2) = 0 → x = +7." }
];

let correctasOxidacion = 0;
let respondidasOxidacion = new Array(ejerciciosOxidacion.length).fill(false);

function cargarOxidacion() {
  const cont = document.getElementById("ejerciciosOxidacion");
  cont.innerHTML = "";

  ejerciciosOxidacion.forEach((ej, i) => {
    const box = document.createElement("div");
    box.style.background = "#f8fafc";
    box.style.border = "1px solid #cbd5e1";
    box.style.borderRadius = "14px";
    box.style.padding = "16px";
    box.style.marginTop = "14px";

    box.innerHTML = `
      <p><strong>${i + 1}) ${ej.formula}</strong></p>
      <p>Número de oxidación de <strong>${ej.elemento}</strong>:</p>
      <input id="ox${i}" type="number" step="1" style="padding:10px; border-radius:10px; border:1px solid #cbd5e1; width:120px;">
      <button onclick="corregirOxidacion(${i})" style="margin-left:8px; padding:10px 14px; border:none; background:#2563eb; color:white; border-radius:10px; cursor:pointer;">Corregir</button>
      <p id="fbOx${i}" style="font-weight:bold;"></p>
    `;

    cont.appendChild(box);
  });

  actualizarResultadoOxidacion();
}

function corregirOxidacion(i) {
  const valor = parseInt(document.getElementById("ox" + i).value);
  const fb = document.getElementById("fbOx" + i);
  const ej = ejerciciosOxidacion[i];

  if (isNaN(valor)) {
    fb.style.color = "#991b1b";
    fb.innerHTML = "Introduce un número.";
    return;
  }

  if (!respondidasOxidacion[i]) {
    respondidasOxidacion[i] = true;
    if (valor === ej.respuesta) correctasOxidacion++;
  }

  if (valor === ej.respuesta) {
    fb.style.color = "#166534";
    fb.innerHTML = "Correcto. " + ej.explicacion;
  } else {
    fb.style.color = "#991b1b";
    fb.innerHTML = "No es correcto. " + ej.explicacion;
  }

  actualizarResultadoOxidacion();
}

function actualizarResultadoOxidacion() {
  const respondidas = respondidasOxidacion.filter(x => x).length;
  document.getElementById("resultadoOxidacion").innerHTML =
    "Puntuación: " + correctasOxidacion + "/" + ejerciciosOxidacion.length +
    " | Respondidas: " + respondidas + "/" + ejerciciosOxidacion.length;
}

function reiniciarOxidacion() {
  correctasOxidacion = 0;
  respondidasOxidacion = new Array(ejerciciosOxidacion.length).fill(false);
  cargarOxidacion();
}

cargarOxidacion();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"20260428154754976IUO","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="quizTradicionalDef" style="font-family: Arial,sans-serif; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 18px; padding: 22px;">
<h2 style="color: #1d4ed8; margin-top: 0;">Practica: nombra el oxoácido</h2>
<p>Elige el nombre tradicional correcto.</p>
<div id="preguntasTradDef"></div>
<button onclick="reiniciarTradDef()" style="margin-top: 18px; background: #2563eb; color: white; border: none; padding: 12px 18px; border-radius: 12px; font-weight: bold; cursor: pointer;"> Reiniciar actividad </button>
<p id="resultadoTradDef" style="font-size: 18px; font-weight: bold; margin-top: 16px;"></p>
</div>
<p>
<script>
const preguntasTradDef = [
{f:"H3BO3", opciones:["ácido boroso","ácido bórico","ácido perbórico","ácido hipoboroso"], c:1, e:"B trabaja con +3 como valencia habitual → ácido bórico."},
{f:"H2CO3", opciones:["ácido carbonoso","ácido carbónico","ácido percarbónico","ácido hipocarbónico"], c:1, e:"C trabaja con +4 como valencia habitual → ácido carbónico."},
{f:"HNO2", opciones:["ácido nitroso","ácido nítrico","ácido hiponitroso","ácido pernítrico"], c:0, e:"N en +3, valencia menor → ácido nitroso."},
{f:"HNO3", opciones:["ácido nitroso","ácido nítrico","ácido nitrogenoso","ácido pernítrico"], c:1, e:"N en +5, valencia mayor → ácido nítrico."},
{f:"H2SO3", opciones:["ácido sulfúrico","ácido sulfuroso","ácido hiposulfuroso","ácido persulfúrico"], c:1, e:"S en +4, valencia menor → ácido sulfuroso."},
{f:"H2SO4", opciones:["ácido sulfuroso","ácido sulfúrico","ácido persulfuroso","ácido sulfhídrico"], c:1, e:"S en +6, valencia mayor → ácido sulfúrico."},
{f:"HClO", opciones:["ácido hipocloroso","ácido cloroso","ácido clórico","ácido perclórico"], c:0, e:"Cl en +1, la menor → ácido hipocloroso."},
{f:"HClO4", opciones:["ácido clórico","ácido cloroso","ácido hipocloroso","ácido perclórico"], c:3, e:"Cl en +7, la mayor → ácido perclórico."},
{f:"HMnO4", opciones:["ácido manganoso","ácido mangánico","ácido permangánico","ácido hipomanganoso"], c:2, e:"Mn en +7 → ácido permangánico."},
{f:"H2Cr2O7", opciones:["ácido crómico","ácido dicrómico","ácido cromoso","ácido percrómico"], c:1, e:"Tiene dos átomos de Cr → ácido dicrómico."}
];

let puntosTradDef = 0;
let contestadasTradDef = new Array(preguntasTradDef.length).fill(false);

function cargarTradDef(){
const cont = document.getElementById("preguntasTradDef");
cont.innerHTML = "";

preguntasTradDef.forEach((p,i)=>{
const box = document.createElement("div");
box.style.background = "white";
box.style.border = "1px solid #cbd5e1";
box.style.borderRadius = "14px";
box.style.padding = "16px";
box.style.marginTop = "14px";

box.innerHTML = "<p><strong>" + (i+1) + ") " + p.f + "</strong></p>";

p.opciones.forEach((op,j)=>{
const b = document.createElement("button");
b.innerHTML = op;
b.style.display = "block";
b.style.width = "100%";
b.style.margin = "8px 0";
b.style.padding = "10px";
b.style.textAlign = "left";
b.style.borderRadius = "10px";
b.style.border = "1px solid #cbd5e1";
b.style.cursor = "pointer";
b.onclick = ()=>corregirTradDef(i,j,b);
box.appendChild(b);
});

const fb = document.createElement("p");
fb.id = "fbTradDef" + i;
fb.style.fontWeight = "bold";
box.appendChild(fb);

cont.appendChild(box);
});

actualizarTradDef();
}

function corregirTradDef(i,j,b){
const p = preguntasTradDef[i];
const fb = document.getElementById("fbTradDef"+i);
const botones = b.parentElement.querySelectorAll("button");

if(!contestadasTradDef[i]){
contestadasTradDef[i] = true;
if(j === p.c) puntosTradDef++;
}

botones.forEach((x,k)=>{
x.disabled = true;
if(k === p.c) x.style.background = "#dcfce7";
else if(k === j) x.style.background = "#fee2e2";
});

fb.innerHTML = (j === p.c ? "Correcto. " : "No es correcto. ") + p.e;
fb.style.color = (j === p.c ? "#166534" : "#991b1b");

actualizarTradDef();
}

function actualizarTradDef(){
const respondidas = contestadasTradDef.filter(x=>x).length;
document.getElementById("resultadoTradDef").innerHTML =
"Puntuación: " + puntosTradDef + "/" + preguntasTradDef.length +
" | Respondidas: " + respondidas + "/" + preguntasTradDef.length;
}

function reiniciarTradDef(){
puntosTradDef = 0;
contestadasTradDef = new Array(preguntasTradDef.length).fill(false);
cargarTradDef();
}

cargarTradDef();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"202604281549372359RD","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="tradicionalEscribir" style="font-family: Arial,sans-serif; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 18px; padding: 22px;">
<h2 style="color: #1d4ed8; margin-top: 0;">Practica: escribe el nombre tradicional</h2>
<p>Escribe el nombre tradicional correcto del oxoácido.</p>
<div id="preguntasEscribirTrad"></div>
<button onclick="reiniciarEscribirTrad()" style="margin-top: 18px; background: #2563eb; color: white; border: none; padding: 12px 18px; border-radius: 12px; font-weight: bold; cursor: pointer;"> Reiniciar actividad </button>
<p id="resultadoEscribirTrad" style="font-size: 18px; font-weight: bold; margin-top: 16px;"></p>
</div>
<p>
<script>
const ejerciciosEscribirTrad = [
{
formula:"HNO3",
respuesta:["acidonitrico","ácidonítrico"],
exp:"N trabaja con +5 (valencia mayor) → terminación -ico → ácido nítrico."
},
{
formula:"H2SO3",
respuesta:["acidosulfuroso","ácidosulfuroso"],
exp:"S trabaja con +4 (valencia menor) → ácido sulfuroso."
},
{
formula:"HClO4",
respuesta:["acidoperclorico","ácidoperclórico"],
exp:"Cl en +7 → máximo estado → prefijo per- y sufijo -ico → ácido perclórico."
},
{
formula:"H3PO3",
respuesta:["acidofosforoso","ácidofosforoso"],
exp:"P en +3 → valencia menor → ácido fosforoso."
},
{
formula:"HMnO4",
respuesta:["acidopermanganico","ácidopermangánico"],
exp:"Mn en +7 → ácido permangánico."
},
{
formula:"H2Cr2O7",
respuesta:["acidodicromico","ácidodicrómico"],
exp:"Contiene dos átomos de Cr → ácido dicrómico."
},
{
formula:"H3AsO4",
respuesta:["acidoarsenico","ácidoarsénico"],
exp:"As en +5 → valencia mayor → ácido arsénico."
},
{
formula:"H3BO3",
respuesta:["acidoborico","ácidobórico"],
exp:"B tiene una valencia habitual → ácido bórico."
}
];

let puntosEscribirTrad = 0;
let respondidasEscribirTrad = new Array(ejerciciosEscribirTrad.length).fill(false);

function normalizarTexto(txt){
return txt
.toLowerCase()
.normalize("NFD")
.replace(/[\u0300-\u036f]/g,"")
.replace(/\s+/g,"");
}

function cargarEscribirTrad(){
const cont = document.getElementById("preguntasEscribirTrad");
cont.innerHTML = "";

ejerciciosEscribirTrad.forEach((p,i)=>{
const box = document.createElement("div");
box.style.background="white";
box.style.border="1px solid #cbd5e1";
box.style.borderRadius="14px";
box.style.padding="16px";
box.style.marginTop="14px";

box.innerHTML=`
<p><strong>${i+1}) ${p.formula}</strong></p>
<input id="respTrad${i}" type="text"
placeholder="Escribe aquí el nombre..."
style="width:100%;padding:10px;border-radius:10px;border:1px solid #cbd5e1;margin-top:8px;">
<button onclick="corregirEscribirTrad(${i})"
style="margin-top:10px;padding:10px 14px;border:none;background:#2563eb;color:white;border-radius:10px;cursor:pointer;">
Corregir
</button>
<p id="fbEscribirTrad${i}" style="font-weight:bold;margin-top:10px;"></p>
`;

cont.appendChild(box);
});

actualizarEscribirTrad();
}

function corregirEscribirTrad(i){
const entrada = document.getElementById("respTrad"+i);
const fb = document.getElementById("fbEscribirTrad"+i);
const valor = normalizarTexto(entrada.value);
const p = ejerciciosEscribirTrad[i];

if(valor===""){
fb.style.color="#991b1b";
fb.innerHTML="Escribe una respuesta.";
return;
}

const correcta = p.respuesta.some(r=>normalizarTexto(r)===valor);

if(!respondidasEscribirTrad[i]){
respondidasEscribirTrad[i]=true;
if(correcta) puntosEscribirTrad++;
}

entrada.disabled=true;

if(correcta){
entrada.style.background="#dcfce7";
fb.style.color="#166534";
fb.innerHTML="✔ Correcto. " + p.exp;
}else{
entrada.style.background="#fee2e2";
fb.style.color="#991b1b";
fb.innerHTML="✘ No es correcto. Respuesta: <strong>" + p.respuesta[1] + "</strong>. " + p.exp;
}

actualizarEscribirTrad();
}

function actualizarEscribirTrad(){
const respondidas = respondidasEscribirTrad.filter(x=>x).length;
document.getElementById("resultadoEscribirTrad").innerHTML =
"Puntuación: " + puntosEscribirTrad + "/" + ejerciciosEscribirTrad.length +
" | Respondidas: " + respondidas + "/" + ejerciciosEscribirTrad.length;
}

function reiniciarEscribirTrad(){
puntosEscribirTrad = 0;
respondidasEscribirTrad = new Array(ejerciciosEscribirTrad.length).fill(false);
cargarEscribirTrad();
}

cargarEscribirTrad();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"20260428155502489PKG","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="tradicionalEscribir2" style="font-family: Arial,sans-serif; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 18px; padding: 22px;">
