{formula:"H3AsO3", respuesta:"ácido arsenioso", exp:"As en +3 → ácido arsenioso."},
{formula:"H3AsO4", respuesta:"ácido arsénico", exp:"As en +5 → ácido arsénico."},
{formula:"HClO", respuesta:"ácido hipocloroso", exp:"Cl en +1 → hipo...oso."},
{formula:"HClO2", respuesta:"ácido cloroso", exp:"Cl en +3 → ...oso."},
{formula:"HClO3", respuesta:"ácido clórico", exp:"Cl en +5 → ...ico."},
{formula:"HClO4", respuesta:"ácido perclórico", exp:"Cl en +7 → per...ico."},
{formula:"HBrO", respuesta:"ácido hipobromoso", exp:"Br en +1 → hipo...oso."},
